(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["learn27"],{"02ff":function(n,r,e){"use strict";e.r(r);var t=function(){var n=this,r=n.$createElement,t=n._self._c||r;return t("markdown",{attrs:{source:e("7724")}})},l=[],s=e("2877"),a={},i=Object(s["a"])(a,t,l,!1,null,null,null);i.options.__file="nginx.vue";r["default"]=i.exports},7724:function(n,r){n.exports="##  Nginx\r\n\r\n### 系统环境\r\n操作系统：版本>=7.0 位数：64\r\n\r\n### 环境调试确认\r\n#### 四项确认\r\n1.确认系统网络\r\n```s\r\nping www.baidu.com\r\n```\r\n2.确认yum可用\r\n```s\r\nyum list|grep gcc\r\n```\r\n3.确认关闭iptables规则\r\n```\r\niptables -L ：查看是否有iptables规则\r\niptables -F ：关闭iptables规则\r\n保险起见\r\niptables -t nat -L\r\niptables -t nat -F\r\n```\r\n4.确认停用selinux\r\n```\r\ngetenforce ：查看selinux是否开启\r\nsetenforce 0 ：关闭selinux\r\n```\r\n#### 两下安装\r\n```\r\nyum -y install gcc gcc-c++ autoconf pcre pcre-devel make automake\r\nyum -y install wget httpd-tools vim\r\n```\r\n#### 一次初始化\r\n```\r\ncd /opt;mkdir app download logs work backup\r\n```\r\n"}}]);